/**
 * 模块职责：依据动态表格注册表构造内部事实层与可见视图的状态提取提示和 JSON Schema。
 * 维护边界：只提取已发生、已显影内容；停用/删除表格不能出现在提示或 Schema 中。
 */
import type { TableDefinition, TableFieldDefinition } from '../constants';
import type { InternalFact, StateSnapshot } from '../types';
import { DEFAULT_TABLE_REGISTRY, enabledTables, normalizeTableRegistry } from '../domain/table-registry';
import { normalizeSnapshot, stateSchemaDescription } from '../domain/snapshot';

function tables(registry?: TableDefinition[]): TableDefinition[] {
  return enabledTables(normalizeTableRegistry(registry?.length ? registry : DEFAULT_TABLE_REGISTRY as TableDefinition[]));
}
function fieldInstruction(field: TableFieldDefinition): string {
  return `${field.key}（${field.label}）：${field.description || '按字段名称填写'}${field.required ? '，必填' : '，无事实可留空'}`;
}

export function stateSystemPrompt(registry?: TableDefinition[]): string {
  const active = tables(registry);
  const tableLines = active.map((table, index) => {
    const fields = table.fields.map(fieldInstruction).join('；');
    return `${index + 1}. ${table.key}｜${table.name}｜用途：${table.purpose}｜字段：${fields}`;
  }).join('\n');
  const keys = active.map((table) => table.key).join('、');
  return `你是“镜渊”事实提取与状态维护器，也是内部事实与动态可见视图维护器。你不续写故事，不推测未显影内容。

输出必须是可直接 JSON.parse 的完整对象，不要 Markdown、解释或思考标签。
根节点固定为 turnSummary、facts、snapshot。
snapshot 只能包含当前启用的表格：${keys || '（无启用表格）'}。禁止输出任何未注册、已删除或已停用表格。

【内部事实层】
facts 每条字段：
- fact_id：稳定事实ID；同一事实更新时沿用。
- event_id：所属事件线ID；同一因果线沿用。即使“活跃事件”视图被删除也必须保留。
- type：事实类别或语义类型，不受表格数量限制。
- title：事实标题。
- occurred：已经确定发生的事实句数组。
- unresolved：尚未解决但正文已明确存在的事项数组。
- status：当前阶段或有效状态。
- time_range：start、end、label；未知可为空字符串。
- related_entities：正文明确关联的人物、物品、技能、区域、组织、制度等。
- keywords：明确名称和别名。
- operation：create、update、append、close、supersede。
- confidence：confirmed、recorded、reported、uncertain。

【事实边界】
1. 只保存当前焦点周围、对后续生成确有作用的活跃事实；不复制全部旧状态。
2. 禁止因人物仅仅出现、围观、听见、喝彩、议论、同场或临时侍从身份而建立状态、关系或事件。
3. 两人对战只保留交战双方、对战事实，以及确实会改变战局或结果的第三方。纯观众及其关系、物品、反应、区域和设定不得进入 facts、snapshot 或世界书视图。
4. 焦点标题不能只写单个人名；禁止自动补全 NPC 隐私、经历、能力、隐藏关系、真实意图和未发生结果。
5. 他人陈述、传闻和推测使用 reported 或 uncertain，不得升级为 confirmed。
6. focus 只记录当前核心冲突、目标或待决事项；同一事实只进入最合适的一张可见表，焦点表不得与状态、事件等表重复。
7. 玩家输入中的行为可以记录为已声明动作；外部结果必须由角色正文或已有可靠事实确认。
8. event_id 是总结和历史重建的稳定主线，不得因事件表被停用而省略。

【可见表格注册表】
${tableLines || '当前没有启用的可见表格；snapshot 输出空对象，但 facts 仍正常维护。'}

【表格维护】
1. snapshot 是 facts 的当前视图，不是唯一数据源。每行使用 factIds 关联内部事实，使用 eventId 关联事件线。
2. 保留未受影响且仍成立的旧行；只有正文明确改变时才更新。
3. source=manual 或 locked=true 的旧行不得覆盖、删除或降级。
4. 正式主体仅在已显影且对连续性有独立价值时进入“状态”角色表；纯旁观者不建立。
5. 场景或地点发生切换时，“时空”中只能有一个当前场景；已离开的旧场景若仍有后续价值，状态必须改为“已离开”或“历史场景”，并提供明确触发词，不得继续标为当前。
6. 过程压缩为当前结果；未决事项不得强行闭合。
7. keywords 只写明确名称、别名或触发词；recall 可包含 any/all/exclude，不是数值权重。

结构示例：
{"turnSummary":"本轮已发生事实摘要","facts":[{"fact_id":"fact_1","event_id":"event_1","type":"event","title":"对战开始","occurred":["甲与乙开始交战"],"unresolved":["胜负未定"],"status":"进行中","time_range":{"start":"当前","end":"","label":"本场对战"},"related_entities":["甲","乙"],"keywords":["甲","乙","对战"],"operation":"update","confidence":"confirmed"}],"snapshot":${stateSchemaDescription(active)}}`;
}

function activeFactPayload(facts: InternalFact[]): Record<string, unknown>[] {
  return facts.map((fact) => ({
    fact_id: fact.factId,
    event_id: fact.eventId,
    occurred: fact.occurredFacts,
    unresolved: fact.unresolvedItems,
    status: fact.status,
    time_range: fact.timeRange,
    related_entities: fact.relatedEntities,
    title: fact.title,
    type: fact.type,
    keywords: fact.keywords,
    confidence: fact.confidence,
    active: fact.active,
  }));
}

export function stateUserPrompt(
  previous: StateSnapshot,
  playerText: string,
  assistantText: string,
  registry?: TableDefinition[],
  internalFacts: InternalFact[] = [],
  repair = false,
): string {
  const active = tables(registry);
  const filteredPrevious = normalizeSnapshot(previous, previous, active, false);
  return `【当前内部活跃事实】
${JSON.stringify(activeFactPayload(internalFacts), null, 2)}

【上一份启用表格视图】
${JSON.stringify(filteredPrevious, null, 2)}

【玩家本轮输入】
${playerText || '（空）'}

【角色本轮正文】
${assistantText}

内部事实层是连续性来源；沿用同一事实的 fact_id 和 event_id，只输出本轮新增、更新、追加、关闭或替代操作。输出更新后的完整启用表格视图，snapshot 不得出现注册表之外的键。${repair ? '\n上一次输出无法解析；这次只输出合法JSON对象。' : ''}`;
}

function scalarSchema(field: TableFieldDefinition): Record<string, any> {
  if (field.type === 'string[]') return { type: 'array', items: { type: 'string' } };
  if (field.type === 'lifecycle') {
    return {
      type: 'object',
      properties: {
        existence: { type: 'string' }, activity: { type: 'string' }, memory: { type: 'string' }, evidenceLevel: { type: 'string' }, evidence: { type: 'string' },
        returnConditions: { type: 'array', items: { type: 'string' } }, returnBlockers: { type: 'array', items: { type: 'string' } },
      },
      required: ['existence', 'activity', 'memory', 'evidenceLevel', 'evidence', 'returnConditions', 'returnBlockers'],
      additionalProperties: false,
    };
  }
  return { type: 'string' };
}

function rowSchema(table: TableDefinition): Record<string, any> {
  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (const field of table.fields) {
    properties[field.key] = scalarSchema(field);
    if (field.required) required.push(field.key);
  }
  properties.factIds = { type: 'array', items: { type: 'string' } };
  properties.eventId = { type: 'string' };
  properties.recall = {
    type: 'object',
    properties: {
      any: { type: 'array', items: { type: 'string' } },
      all: { type: 'array', items: { type: 'string' } },
      exclude: { type: 'array', items: { type: 'string' } },
    },
    required: ['any', 'all', 'exclude'], additionalProperties: false,
  };
  required.push('factIds', 'eventId', 'recall');
  return { type: 'object', properties, required: [...new Set(required)], additionalProperties: false };
}

export function stateJsonSchema(registry?: TableDefinition[]): Record<string, any> {
  const active = tables(registry);
  const snapshotProperties = Object.fromEntries(active.map((table) => [table.key, { type: 'array', items: rowSchema(table) }]));
  return {
    name: 'MirrorAbyssStateResultV23',
    description: '镜渊内部事实层与动态可见表格视图',
    strict: true,
    value: {
      type: 'object',
      properties: {
        turnSummary: { type: 'string' },
        facts: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              fact_id: { type: 'string' }, event_id: { type: 'string' }, type: { type: 'string' }, title: { type: 'string' },
              occurred: { type: 'array', items: { type: 'string' } }, unresolved: { type: 'array', items: { type: 'string' } }, status: { type: 'string' },
              time_range: { type: 'object', properties: { start: { type: 'string' }, end: { type: 'string' }, label: { type: 'string' } }, required: ['start', 'end', 'label'], additionalProperties: false },
              related_entities: { type: 'array', items: { type: 'string' } }, keywords: { type: 'array', items: { type: 'string' } },
              operation: { type: 'string' }, confidence: { type: 'string' },
            },
            required: ['fact_id', 'event_id', 'type', 'title', 'occurred', 'unresolved', 'status', 'time_range', 'related_entities', 'keywords', 'operation', 'confidence'],
            additionalProperties: false,
          },
        },
        snapshot: { type: 'object', properties: snapshotProperties, required: active.map((table) => table.key), additionalProperties: false },
      },
      required: ['turnSummary', 'facts', 'snapshot'], additionalProperties: false,
    },
  };
}
