/**
 * 模块职责：执行结构化任务、Schema 兼容回退与最多一次格式修复。
 * 维护边界：Schema 失败只允许一次无 Schema 回退；取消和提交失效不得触发兼容重试。
 */
import type { TaskKind } from '../constants';
import { getSettings } from '../core/context';
import { JsonObjectParseError, jsonPreview, parseJsonObject, safeText, toErrorMessage } from '../core/utils';
import type { GenerateOptions } from '../types';
import { describeTaskConnection, generateTask, rememberJsonSchemaUnsupported, shouldSkipJsonSchema } from './generator';

export interface StructuredGenerationOptions extends GenerateOptions {
  task: TaskKind;
  structureDescription: string;
  allowRepair?: boolean;
}

function repairSystemPrompt(structureDescription: string): string {
  return `你是JSON格式修复器。你不执行原任务、不补充新事实、不解释内容，只把给定模型输出转换成一个合法JSON对象。

要求：
1. 保留原输出中已经表达的语义，不自行重做审核、总结或状态提取。
2. 删除Markdown代码围栏、解释、前言、结语和思考标签。
3. 修复缺失引号、尾随逗号、全角标点等格式问题。
4. 输出必须能被JSON.parse直接解析，根节点必须是对象。
5. 只输出JSON对象，禁止输出任何额外文字。

【目标结构】
${structureDescription}`;
}

function repairUserPrompt(raw: string): string {
  return `【需要修复的原始输出】
${safeText(raw, 80000)}`;
}

const TASK_LABELS: Record<TaskKind, string> = {
  audit: '规则审核',
  revision: '定向修正',
  state: '状态表',
  smallSummary: '小总结',
  largeSummary: '大总结',
};

function isCancelledRequest(error: unknown): boolean {
  return error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name);
}

function structuredError(task: TaskKind, error: unknown, raw: string): Error {
  const connection = describeTaskConnection(task);
  const preview = error instanceof JsonObjectParseError ? error.preview : jsonPreview(raw);
  const detail = toErrorMessage(error);
  return new Error(`${TASK_LABELS[task]}未返回有效JSON结构（${connection}）。${detail}${preview ? `；返回片段：${preview}` : ''}`);
}

export async function repairStructuredOutput(
  task: TaskKind,
  raw: string,
  structureDescription: string,
): Promise<Record<string, any>> {
  const repaired = await generateTask({
    task,
    systemPrompt: repairSystemPrompt(structureDescription),
    prompt: repairUserPrompt(raw),
  });
  return parseJsonObject(repaired);
}

async function generateWithSchemaFallback(options: StructuredGenerationOptions): Promise<string> {
  if (options.jsonSchema && shouldSkipJsonSchema(options.task)) {
    return generateTask({ ...options, jsonSchema: undefined });
  }

  let schemaFailure: unknown;
  try {
    const raw = await generateTask(options);
    if (!options.jsonSchema || raw.trim() !== '{}') return raw;
    schemaFailure = new Error('结构化输出返回空对象，当前模型或接口可能不支持JSON Schema');
  } catch (error) {
    if (!options.jsonSchema || isCancelledRequest(error)) throw error;
    schemaFailure = error;
  }

  try {
    const fallback = await generateTask({ ...options, jsonSchema: undefined });
    rememberJsonSchemaUnsupported(options.task);
    return fallback;
  } catch (fallbackError) {
    if (isCancelledRequest(fallbackError)) throw fallbackError;
    throw new Error(
      `${TASK_LABELS[options.task]}请求失败（${describeTaskConnection(options.task)}）。结构化请求：${toErrorMessage(schemaFailure)}；无Schema回退：${toErrorMessage(fallbackError)}`,
    );
  }
}

/**
 * 结构化任务按“Schema → 一次无 Schema 兼容回退 → 可选一次格式修复”执行。
 * 该顺序是有限兼容，不允许形成循环调用。
 */
export async function generateStructuredTask(options: StructuredGenerationOptions): Promise<Record<string, any>> {
  const raw = await generateWithSchemaFallback(options);
  try {
    return parseJsonObject(raw);
  } catch (firstError) {
    const allowRepair = options.allowRepair ?? getSettings().repairInvalidJsonOnce;
    if (!allowRepair) throw structuredError(options.task, firstError, raw);
    try {
      return await repairStructuredOutput(options.task, raw, options.structureDescription);
    } catch (repairError) {
      if (repairError instanceof Error && repairError.message.startsWith(`${TASK_LABELS[options.task]}未返回有效JSON结构`)) {
        throw repairError;
      }
      throw structuredError(options.task, repairError, raw);
    }
  }
}
