/**
 * 模块职责：渲染每条角色消息下方的阶段状态与操作入口。
 * 维护边界：UI 只展示 artifact 状态；所有阶段按钮必须调用 pipeline 公开入口。
 */
import { getChat, getSettings, latestAssistantIndex, toast } from '../core/context';
import { escapeHtml, toErrorMessage } from '../core/utils';
import { forceSummary, getArtifactAt, latestSnapshotArtifact, processMessage, retryStage, subscribePipeline } from '../pipeline/pipeline';
import type { MessageArtifact, StageRecord } from '../types';
import { openWorkspace } from './workspace';
import { applyAuditVisibility } from '../pipeline/audit';
import { snapshotRowCount } from '../domain/snapshot';

function stageLabel(stage: StageRecord): string {
  const map: Record<string, string> = {
    idle: '等待', queued: '排队', running: '处理中', success: '成功', failed: '失败', cancelled: '已取消', skipped: '跳过', blocked: '阻断',
  };
  return map[stage?.status] || '等待';
}

function tone(stage: StageRecord): string {
  if (stage?.status === 'success' || stage?.status === 'skipped') return 'success';
  if (stage?.status === 'failed' || stage?.status === 'blocked') return 'danger';
  if (stage?.status === 'running' || stage?.status === 'queued') return 'working';
  return 'neutral';
}

function findMessageElement(index: number): HTMLElement | null {
  return document.querySelector<HTMLElement>(`.mes[mesid="${index}"], .mes[data-message-id="${index}"], #chat .mes:nth-of-type(${index + 1})`);
}

export type MessageStageAction = 'audit' | 'revision' | 'state' | 'small' | 'large' | 'sync';

/** 按钮始终渲染；这里只决定能否点击，避免失败前完全找不到对应操作。 */
export function messageStageAvailability(index: number, artifact: MessageArtifact): Record<MessageStageAction, boolean> {
  const settings = getSettings();
  const latestText = index === latestAssistantIndex();
  const latestSnapshot = index === latestSnapshotArtifact()?.index;
  const notBusy = (status: string | undefined) => !['queued', 'running'].includes(status ?? 'idle');
  return {
    audit: Boolean(settings.enabled && latestText && settings.auditEnabled && settings.auditPrompt.trim() && notBusy(artifact.stages.audit.status)),
    revision: Boolean(settings.enabled && latestText && artifact.audit && !artifact.audit.passed && artifact.audit.decision !== 'block' && notBusy(artifact.stages.revision.status)),
    state: Boolean(settings.enabled && latestText && (!settings.auditEnabled || artifact.audit?.passed) && notBusy(artifact.stages.state.status)),
    small: Boolean(settings.enabled && latestSnapshot && artifact.stages.state.status === 'success' && notBusy(artifact.stages.summary.status)),
    large: Boolean(settings.enabled && latestSnapshot && artifact.stages.state.status === 'success' && notBusy(artifact.stages.summary.status)),
    sync: Boolean(settings.enabled && latestSnapshot && artifact.stages.state.status === 'success' && notBusy(artifact.stages.sync.status)),
  };
}

const pendingRetryIndexes = new Set<number>();

function flowStageHtml(order: number, label: string, stage: StageRecord): string {
  const status = stageLabel(stage);
  const symbol = stage?.status === 'success' || stage?.status === 'skipped'
    ? '✓'
    : stage?.status === 'failed' || stage?.status === 'blocked'
      ? '!'
      : stage?.status === 'running' || stage?.status === 'queued'
        ? '…'
        : String(order);
  return `<span class="ma11-flow-stage ${tone(stage)}"><em>${symbol}</em><span><small>${label}</small><b>${status}</b></span></span>`;
}

export function panelHtml(index: number, artifact: MessageArtifact): string {
  const rows = snapshotRowCount(artifact.snapshot, getSettings().tableRegistry, true);
  const error = Object.values(artifact.stages).find((stage) => stage.error)?.error;
  const retrying = pendingRetryIndexes.has(index);
  const latestText = index === latestAssistantIndex();
  const latestSnapshot = index === latestSnapshotArtifact()?.index;
  const available = messageStageAvailability(index, artifact);
  const enabled = (action: MessageStageAction) => !retrying && available[action] ? '' : 'disabled';
  const chainBusy = Object.values(artifact.stages).some((stage) => ['queued', 'running'].includes(stage.status));
  const chainFailed = Object.values(artifact.stages).some((stage) => ['failed', 'blocked'].includes(stage.status));
  const chainComplete = artifact.stages.state.status === 'success'
    && ['success', 'skipped'].includes(artifact.stages.summary.status)
    && ['success', 'skipped'].includes(artifact.stages.sync.status);
  const chainState = chainBusy ? '自动处理中' : chainFailed ? '需要处理' : chainComplete ? '本轮已完成' : '等待自动继续';
  const chainHint = chainBusy
    ? '镜渊会按顺序自动继续，不需要逐个点击。'
    : chainComplete
      ? '审核、表格与派生发布已完成。'
      : '按钮只用于恢复中断链；下方单步工具用于排错。';
  return `
    <div class="ma11-message-panel" data-ma-index="${index}">
      <button class="ma11-message-summary" type="button" data-ma-action="open">
        <span class="ma11-message-title">镜渊自动处理</span>
        <span class="ma11-message-count">${rows} 条状态</span>
      </button>
      <div class="ma11-chain-state ${chainFailed ? 'danger' : chainBusy ? 'working' : chainComplete ? 'success' : 'neutral'}">
        <b>${chainState}</b><span>${chainHint}</span>
      </div>
      <div class="ma11-flow" aria-label="审核到世界书的处理进度">
        ${flowStageHtml(1, '审核', artifact.stages.audit)}<i>›</i>
        ${flowStageHtml(2, '修正', artifact.stages.revision)}<i>›</i>
        ${flowStageHtml(3, '表格', artifact.stages.state)}<i>›</i>
        ${flowStageHtml(4, '总结', artifact.stages.summary)}<i>›</i>
        ${flowStageHtml(5, '世界书', artifact.stages.sync)}
      </div>
      ${artifact.audit && !artifact.audit.passed ? `<div class="ma11-message-error">${escapeHtml(artifact.audit.reason)}</div>` : error ? `<div class="ma11-message-error">${escapeHtml(error)}</div>` : ''}
      ${latestText ? `<div class="ma11-message-primary-actions">
        <button class="ma11-primary-action" data-ma-auto-continue ${retrying || chainBusy || chainComplete ? 'disabled' : ''}>${chainBusy ? '自动处理中，请稍候' : chainComplete ? '自动流程已完成' : '继续自动流程'}</button>
        <small>会检查已有成功状态，从第一个失效阶段继续，不重复调用已通过的审核。</small>
      </div>
      <details class="ma11-message-tools">
        <summary>单步排错工具（正常游玩无需使用）</summary>
        <div class="ma11-message-actions ma11-message-stage-actions" aria-label="镜渊分阶段操作">
          <button data-ma-stage-action="audit" ${enabled('audit')}>仅审核</button>
          <button data-ma-stage-action="revision" ${enabled('revision')}>仅修正</button>
          <button data-ma-stage-action="state" ${enabled('state')}>仅生成表格</button>
          <button data-ma-stage-action="small" ${enabled('small')}>立即小总结</button>
          <button data-ma-stage-action="large" ${enabled('large')}>立即大总结</button>
          <button data-ma-stage-action="sync" ${enabled('sync')}>立即同步</button>
        </div>
      </details>` : ''}
      <div class="ma11-message-actions">
        ${retrying ? '<button disabled>处理中…</button>' : ''}
        ${!retrying && latestText && artifact.stages.audit.status === 'failed' ? '<button data-ma-retry="audit">重试审核</button>' : ''}
        ${!retrying && latestText && ['failed','blocked'].includes(artifact.stages.revision?.status ?? 'idle') ? '<button data-ma-retry="revision">重试定向修正</button>' : ''}
        ${!retrying && latestText && artifact.stages.state.status === 'failed' ? '<button data-ma-retry="state">重试表格</button>' : ''}
        ${!retrying && latestSnapshot && artifact.stages.summary.status === 'failed' ? '<button data-ma-retry="summary">重试总结</button>' : ''}
        ${!retrying && latestSnapshot && artifact.stages.sync.status === 'failed' ? '<button data-ma-retry="sync">重试同步</button>' : ''}
      </div>
    </div>`;

}

export function renderMessagePanel(index: number): void {
  const messageElement = findMessageElement(index);
  if (!messageElement) return;
  const settings = getSettings();
  const artifact = getArtifactAt(index);
  applyAuditVisibility(
    index,
    Boolean(settings.enabled && artifact?.hiddenByAudit),
    Boolean(settings.enabled && artifact?.audit && !artifact.audit.passed && !artifact.hiddenByAudit),
  );
  messageElement.querySelector(':scope > .ma11-message-panel')?.remove();
  if (!settings.showMessagePanel) return;
  if (!artifact) return;
  messageElement.insertAdjacentHTML('beforeend', panelHtml(index, artifact));
}

export function renderAllMessagePanels(): void {
  getChat().forEach((message, index) => {
    if (!message?.is_user) renderMessagePanel(index);
  });
}

let installed = false;
export function installMessagePanelHandlers(): () => void {
  if (installed) return () => undefined;
  installed = true;
  const click = (event: Event) => {
    const target = event.target as HTMLElement;
    const panel = target.closest<HTMLElement>('.ma11-message-panel');
    if (!panel) return;
    const index = Number(panel.dataset.maIndex);
    if (target.closest('[data-ma-action="open"]')) openWorkspace('overview', index);
    if (target.closest('[data-ma-auto-continue]')) {
      if (pendingRetryIndexes.has(index)) return;
      pendingRetryIndexes.add(index);
      renderMessagePanel(index);
      toast('info', '正在从第一个失效阶段继续处理');
      void processMessage(index, false).catch((error) => {
        toast('error', toErrorMessage(error));
      }).finally(() => {
        pendingRetryIndexes.delete(index);
        renderMessagePanel(index);
      });
      return;
    }
    const stageAction = target.closest<HTMLElement>('[data-ma-stage-action]')?.dataset.maStageAction as MessageStageAction | undefined;
    if (stageAction) {
      if (pendingRetryIndexes.has(index)) return;
      pendingRetryIndexes.add(index);
      renderMessagePanel(index);
      toast('info', '已提交阶段任务，请稍候');
      const task = stageAction === 'small' || stageAction === 'large'
        ? forceSummary(index, stageAction)
        : retryStage(index, stageAction);
      void task.catch((error) => {
        toast('error', toErrorMessage(error));
      }).finally(() => {
        pendingRetryIndexes.delete(index);
        renderMessagePanel(index);
      });
      return;
    }
    const retry = target.closest<HTMLElement>('[data-ma-retry]')?.dataset.maRetry as any;
    if (retry) {
      if (pendingRetryIndexes.has(index)) return;
      pendingRetryIndexes.add(index);
      renderMessagePanel(index);
      toast('info', '已提交重试，请稍候');
      void retryStage(index, retry).catch((error) => {
        toast('error', toErrorMessage(error));
      }).finally(() => {
        pendingRetryIndexes.delete(index);
        renderMessagePanel(index);
      });
    }
  };
  document.addEventListener('click', click);
  const unsubscribe = subscribePipeline((index) => renderMessagePanel(index));
  return () => {
    installed = false;
    pendingRetryIndexes.clear();
    document.removeEventListener('click', click);
    unsubscribe();
  };
}
