/**
 * 模块职责：插件启动、禁用、重启、事件装卸与调试 API 的生命周期总控。
 * 维护边界：生命周期代次用于阻止旧初始化继续落地；禁用时必须停止接收任务并取消活动请求。
 */
import { DISPLAY_NAME, MODULE_NAME, VERSION } from '../constants';
import { getContext, getSettings, isProcessableAssistantMessage, saveSettings, toast, tryGetContext } from '../core/context';
import { clearAllStorage } from '../storage/repository';
import { installPipelineEventHandlers, latestArtifact, processMessage } from '../pipeline/pipeline';
import { resetLorebookRuntime } from '../pipeline/lorebook';
import { installMessagePanelHandlers, renderAllMessagePanels } from '../ui/message-panel';
import { diagnosticReport } from '../ui/diagnostics';
import { mountOptionalTopButton, mountSettingsPanel } from '../ui/settings-panel';
import { disposeWorkspace, openWorkspace, refreshWorkspace, resetWorkspaceContext } from '../ui/workspace';
import { abortActiveRequests, setRequestAcceptance } from '../core/requests';
import { taskQueue } from '../pipeline/task-queue';

let state: 'idle' | 'initializing' | 'ready' | 'error' = 'idle';
let cleanupPipeline: (() => void) | null = null;
let cleanupPanels: (() => void) | null = null;
let cleanupUiEvents: (() => void) | null = null;
let appReadyHandlerInstalled = false;
let appReadyContext: any | null = null;
let appReadyHandler: (() => void) | null = null;
let extensionEnabled = true;
// 每次 shutdown 都递增代次，使旧 initialize continuation 即使恢复也不能继续挂载 UI 或监听器。
let lifecycleGeneration = 0;
let debugRegistered = false;
let startupAttempts = 0;
let lastError: unknown = null;
const MAX_STARTUP_ATTEMPTS = 20;

/** 暴露稳定调试入口；这些名称可能被用户脚本和诊断流程依赖。 */
function exposeApi(): void {
  (globalThis as any).MirrorAbyss = {
    version: VERSION,
    open: (tab = 'overview') => {
      if (!extensionEnabled) throw new Error('镜渊插件当前已禁用');
      return openWorkspace(tab);
    },
    processLatest: async () => {
      if (!extensionEnabled) throw new Error('镜渊插件当前已禁用');
      if (!getSettings().enabled) throw new Error('镜渊已关闭，请先启用');
      const context = getContext();
      const index = [...(context.chat ?? [])].map((_: any, i: number) => i).reverse().find((i: number) => isProcessableAssistantMessage(context.chat[i]));
      if (index === undefined) throw new Error('没有可整理的AI正文');
      return processMessage(index, false);
    },
    diagnostics: diagnosticReport,
    restart: restartPlugin,
    getState: () => ({ state, lastError: lastError instanceof Error ? lastError.message : String(lastError || '') }),
  };
}

export async function restartPlugin(): Promise<void> {
  shutdown();
  taskQueue.resetRuntime();
  resetLorebookRuntime();
  extensionEnabled = true;
  startupAttempts = 0;
  installAppReadyHandler();
}

function showFatal(error: unknown): void {
  document.querySelector('#ma11-fatal')?.remove();
  const button = document.createElement('button');
  button.id = 'ma11-fatal';
  button.className = 'ma11-fatal';
  button.type = 'button';
  button.textContent = '镜渊启动失败｜查看诊断';
  button.title = error instanceof Error ? error.message : String(error);
  button.addEventListener('click', () => openWorkspace('diagnostics'));
  document.body.appendChild(button);
}

export async function initialize(): Promise<void> {
  if (!extensionEnabled) return;
  if (state === 'ready' || state === 'initializing') return;
  const generation = lifecycleGeneration;
  state = 'initializing';
  lastError = null;
  exposeApi();
  try {
    const settings = getSettings();
    setRequestAcceptance(settings.enabled);
    taskQueue.setAccepting(settings.enabled);
    await mountSettingsPanel(() => extensionEnabled && generation === lifecycleGeneration);
    if (!extensionEnabled || generation !== lifecycleGeneration) return;
    mountOptionalTopButton();
    cleanupPipeline ||= installPipelineEventHandlers();
    cleanupPanels ||= installMessagePanelHandlers();
    renderAllMessagePanels();

    const context = getContext();
    if (!cleanupUiEvents) {
      const rerender = () => {
        renderAllMessagePanels();
        refreshWorkspace();
      };
      const resetAndRerender = () => {
        resetWorkspaceContext();
        rerender();
      };
      context.eventSource.on(context.event_types.CHARACTER_MESSAGE_RENDERED, rerender);
      context.eventSource.on(context.event_types.CHAT_CHANGED, resetAndRerender);
      context.eventSource.on(context.event_types.MESSAGE_DELETED, resetAndRerender);
      cleanupUiEvents = () => {
        context.eventSource.removeListener?.(context.event_types.CHARACTER_MESSAGE_RENDERED, rerender);
        context.eventSource.removeListener?.(context.event_types.CHAT_CHANGED, resetAndRerender);
        context.eventSource.removeListener?.(context.event_types.MESSAGE_DELETED, resetAndRerender);
      };
    }

    if (!debugRegistered && typeof context.registerDebugFunction === 'function') {
      context.registerDebugFunction(
        'mirror_abyss_diagnostics',
        'Mirror Abyss Diagnostics',
        'Open the Mirror Abyss diagnostics panel',
        () => {
          if (!extensionEnabled) throw new Error('镜渊插件当前已禁用');
          openWorkspace('diagnostics');
        },
      );
      debugRegistered = true;
    }

    document.querySelector('#ma11-fatal')?.remove();
    state = 'ready';
    toast('success', `已启动 ${VERSION}`);
  } catch (error) {
    if (!extensionEnabled || generation !== lifecycleGeneration) return;
    state = 'error';
    lastError = error;
    console.error('[MirrorAbyss] initialization failed', error);
    showFatal(error);
  }
}

export function installAppReadyHandler(): void {
  if (!extensionEnabled) return;
  if (appReadyHandlerInstalled) return;
  const context = tryGetContext();
  if (!context) {
    startupAttempts += 1;
    if (startupAttempts < MAX_STARTUP_ATTEMPTS) {
      window.setTimeout(installAppReadyHandler, 250);
    } else {
      const error = new Error('等待SillyTavern上下文超时，请刷新页面后重试');
      state = 'error';
      lastError = error;
      showFatal(error);
    }
    return;
  }
  startupAttempts = 0;
  appReadyHandlerInstalled = true;
  appReadyContext = context;
  appReadyHandler = () => {
    if (!extensionEnabled) return;
    void initialize();
  };
  context.eventSource.on(context.event_types.APP_READY, appReadyHandler);
  // Third-party extensions may be loaded after APP_READY, so initialization is
  // also attempted immediately. initialize() is idempotent.
  void initialize();
}

export async function cleanData(): Promise<void> {
  await clearAllStorage();
  const context = tryGetContext();
  if (context?.extensionSettings?.[MODULE_NAME]) delete context.extensionSettings[MODULE_NAME];
  context?.saveSettingsDebounced?.();
}

export function onEnable(): void {
  extensionEnabled = true;
  startupAttempts = 0;
  installAppReadyHandler();
}

function shutdown(): void {
  lifecycleGeneration += 1;
  extensionEnabled = false;
  taskQueue.setAccepting(false);
  setRequestAcceptance(false);
  abortActiveRequests();
  resetLorebookRuntime();
  cleanupPipeline?.();
  cleanupPanels?.();
  cleanupUiEvents?.();
  cleanupPipeline = null;
  cleanupPanels = null;
  cleanupUiEvents = null;
  if (appReadyContext && appReadyHandler) {
    appReadyContext.eventSource.removeListener?.(appReadyContext.event_types.APP_READY, appReadyHandler);
  }
  appReadyContext = null;
  appReadyHandler = null;
  appReadyHandlerInstalled = false;
  document.querySelector('#ma11-top-button')?.remove();
  disposeWorkspace();
  document.querySelector('#ma11-settings-root')?.remove();
  document.querySelector('#ma11-fatal')?.remove();
  document.querySelectorAll('.ma11-message-panel').forEach((element) => element.remove());
  document.querySelectorAll('.ma11-audit-hidden-message, .ma11-audit-marked-message').forEach((element) => {
    element.classList.remove('ma11-audit-hidden-message');
    element.classList.remove('ma11-audit-marked-message');
  });
  state = 'idle';
}

export function onDisable(): void {
  shutdown();
}

export function onActivate(): void {
  extensionEnabled = true;
  exposeApi();
  installAppReadyHandler();
}

export async function onInstall(): Promise<void> {
  exposeApi();
}

export async function onUpdate(): Promise<void> {
  const settings = tryGetContext() ? getSettings() : null;
  if (settings) {
    settings.migration.legacyChecked = false;
    saveSettings();
  }
}

export async function onClean(): Promise<void> {
  await cleanData();
}

export async function onDelete(): Promise<void> {
  shutdown();
}
