/**
 * 模块职责：构造按事件线的小总结，以及“上一版大总结 + 未固化小总结”的大总结提示。
 * 维护边界：不读取全部聊天正文，不依据可见表格重新推断事实。
 */
import type { InternalFact, SummaryArtifact } from '../types';

export function smallSummarySystemPrompt(): string {
  return `你是镜渊阶段沉降结算器，也是按 event_id 工作的事件线小总结器。只输出合法JSON对象，不续写，不推测，不把未发生结果写死。
小总结按一个 event_id 汇总已经发生的事件线，不是聊天轮次流水账，也不是当前表格压缩。
必须保留：起因、已发生的关键经过、已产生的变化、当前结果、尚未解决事项、对后续仍有效的影响。
必须删除：重复动作、气氛描写、无因果作用的旁观者、无后续意义的临时反应、已被新事实覆盖的旧表述。
事件未结束时，只总结已确定发生的部分，并明确未解决事项。旁观者、观众、路人、喝彩、议论和同场者不得进入总结，除非其行为改变事件结果。
输出字段固定为 title、summary、keywords、unresolved。可见表退出由代码按 event_id / fact_id 安全处理，不由你指定行号。`;
}

export function smallSummaryPrompt(eventId: string, facts: InternalFact[]): string {
  const payload = facts.map((fact) => ({
    fact_id: fact.factId,
    event_id: fact.eventId,
    source_message_ids: fact.sourceMessageIds,
    title: fact.title,
    occurred: fact.occurredFacts,
    unresolved: fact.unresolvedItems,
    status: fact.status,
    time_range: fact.timeRange,
    related_entities: fact.relatedEntities,
    keywords: fact.keywords,
    confidence: fact.confidence,
  }));
  return `为 event_id=${eventId} 生成一条事件线小总结。
只使用下列内部事实，不读取或补全聊天正文。按因果顺序合并同义事实，保留仍有效的结果和未决事项。

【内部事实】
${JSON.stringify(payload, null, 2)}

只输出：{"title":"...","summary":"...","keywords":["..."],"unresolved":["..."]}`;
}

export function largeSummarySystemPrompt(): string {
  return '你是镜渊长期沉降结算器，也是长期因果固化器。只输出合法JSON对象。输入只能是上一版大总结和尚未固化的小总结；不得重新读取聊天、展开动作细节或补全未显影内容。';
}

export function largeSummaryPrompt(summaries: SummaryArtifact[], previousLarge?: SummaryArtifact): string {
  const source = summaries.map((item) => ({ id: item.id, event_id: item.eventId, title: item.title, summary: item.summary, unresolved: item.unresolvedItems ?? [], keywords: item.keywords })).map((item) => JSON.stringify(item)).join('\n');
  const previous = previousLarge ? JSON.stringify({ id: previousLarge.id, title: previousLarge.title, summary: previousLarge.summary, keywords: previousLarge.keywords }) : '（无）';
  return `把上一版大总结与本批尚未固化的小总结合并为新的累计长期总结。
职责：固化已经发生的事实；合并同一长期因果线；去重和进一步概括；保留稳定结果和未解决事项。
不得重做全部聊天总结，不得重新展开动作细节，不得补全未发生或未显影内容，不得消费输入之外的小总结。没有介入或改变长期因果的旁观信息必须删除。

【上一版大总结】
${previous}

【尚未固化的小总结】
${source || '（无）'}

只输出：{"title":"...","summary":"...","keywords":["..."]}`;
}
