/**
 * 模块职责：定义消息 artifact 与聊天级 ChatState 的存储边界，并迁移 rc.19 事实/总结数据。
 * 维护边界：消息结果附着 message.extra；内部事实与消费标记写入当前 chatMetadata，并在保存前后校验 chatKey。
 */
import { MODULE_NAME } from '../constants';
import { currentChatKey, getChat, getChatMetadataNamespace, getSettings } from '../core/context';
import { assertChatCommitCurrent, persistChatFor, persistMetadataFor } from '../core/commit-guard';
import { nowIso } from '../core/utils';
import { mergeInternalFacts, migrateLegacyConsumption, normalizeInternalFacts } from '../domain/internal-facts';
import { normalizeSnapshot } from '../domain/snapshot';
import type { ChatState, MessageArtifact, SummaryArtifact } from '../types';

export function emptyChatState(chatKey: string): ChatState {
  return {
    schemaVersion: 2,
    chatKey,
    processedMessageKeys: [],
    internalFacts: [],
    smallSummaries: [],
    largeSummaries: [],
    lastSyncStatus: 'idle',
    migration: { dynamicTablesV23: false, internalFactsV23: false },
    updatedAt: nowIso(),
  };
}

function normalizeSummaryArrays(value: unknown, kind: 'small' | 'large'): SummaryArtifact[] {
  if (!Array.isArray(value)) return [];
  return value.filter((item) => item && typeof item === 'object').map((item: any) => ({
    ...item,
    kind,
    sourceKeys: Array.isArray(item.sourceKeys) ? [...new Set(item.sourceKeys.map(String))] : [],
    sourceFactIds: Array.isArray(item.sourceFactIds) ? [...new Set(item.sourceFactIds.map(String))] : undefined,
    sourceSummaryIds: Array.isArray(item.sourceSummaryIds) ? [...new Set(item.sourceSummaryIds.map(String))] : undefined,
    eventIds: Array.isArray(item.eventIds) ? [...new Set(item.eventIds.map(String))] : undefined,
    unresolvedItems: Array.isArray(item.unresolvedItems) ? [...new Set(item.unresolvedItems.map(String))] : undefined,
  })) as SummaryArtifact[];
}

interface ChatStateMigrationResult { state: ChatState; artifactViewsChanged: boolean; metadataChanged: boolean; }

/** 将 rc.19 artifact 事实包与固定九表迁入聊天级内部事实层和默认十表视图。 */
function migrateChatState(raw: ChatState | undefined, chatKey: string): ChatStateMigrationResult {
  const state = raw && raw.chatKey === chatKey ? raw : emptyChatState(chatKey);
  const previousSchema = Number(state.schemaVersion) || 1;
  const needsViewMigration = state.migration?.dynamicTablesV23 !== true;
  const needsFactMigration = state.migration?.internalFactsV23 !== true;
  let artifactViewsChanged = false;
  state.schemaVersion = 2;
  state.processedMessageKeys = Array.isArray(state.processedMessageKeys) ? [...new Set(state.processedMessageKeys.map(String))] : [];
  state.smallSummaries = normalizeSummaryArrays(state.smallSummaries, 'small');
  state.largeSummaries = normalizeSummaryArrays(state.largeSummaries, 'large');
  let facts = normalizeInternalFacts(state.internalFacts);
  const registry = getSettings().tableRegistry;
  for (const message of getChat()) {
    const artifact = message?.extra?.[MODULE_NAME] as MessageArtifact | undefined;
    if (!artifact || artifact.chatKey !== chatKey) continue;
    if (needsViewMigration && artifact.snapshot) {
      const before = JSON.stringify(artifact.snapshot);
      artifact.snapshot = normalizeSnapshot(artifact.snapshot, artifact.snapshot, registry);
      if (JSON.stringify(artifact.snapshot) !== before) artifactViewsChanged = true;
    }
    if (!needsFactMigration || !artifact.factPackage?.facts?.length) continue;
    const incoming = normalizeInternalFacts(artifact.factPackage.facts, artifact.messageKey);
    facts = mergeInternalFacts(facts, incoming, artifact.factPackage.facts);
  }
  migrateLegacyConsumption(facts, state.smallSummaries, state.largeSummaries);
  state.internalFacts = facts;
  state.migration = { ...(state.migration ?? {}), dynamicTablesV23: true, internalFactsV23: true };
  state.updatedAt ||= nowIso();
  return {
    state,
    artifactViewsChanged,
    metadataChanged: previousSchema !== 2 || needsViewMigration || needsFactMigration,
  };
}

/** Canonical message artifacts live on message.extra. */
export async function putArtifact(_artifact: MessageArtifact): Promise<void> {
  // The live artifact object is already attached to the SillyTavern message.
}

export async function getChatState(chatKey: string): Promise<ChatState> {
  assertChatCommitCurrent(chatKey, '聊天已切换，不读取旧聊天状态');
  const namespace = getChatMetadataNamespace();
  const migration = migrateChatState(namespace.state as ChatState | undefined, chatKey);
  namespace.state = migration.state;
  if (migration.artifactViewsChanged) await persistChatFor(chatKey);
  if (migration.metadataChanged) await persistMetadataFor(chatKey);
  return namespace.state as ChatState;
}

/** ChatState 只能写入其自身 chatKey 对应的当前聊天 metadata。 */
export async function putChatState(state: ChatState): Promise<void> {
  assertChatCommitCurrent(state.chatKey, '聊天已切换，不写入旧聊天状态');
  state.schemaVersion = 2;
  state.internalFacts = normalizeInternalFacts(state.internalFacts);
  migrateLegacyConsumption(state.internalFacts, state.smallSummaries, state.largeSummaries);
  state.updatedAt = nowIso();
  const namespace = getChatMetadataNamespace();
  namespace.state = state;
  namespace.updatedAt = state.updatedAt;
  await persistMetadataFor(state.chatKey);
}

export async function clearAllStorage(chatKey = currentChatKey()): Promise<void> {
  assertChatCommitCurrent(chatKey, '聊天已切换，不清理旧聊天状态');
  const namespace = getChatMetadataNamespace();
  delete namespace.state;
  delete namespace.lorebookName;
  namespace.updatedAt = nowIso();
  await persistMetadataFor(chatKey);
}
