/**
 * 模块职责：构造审核系统提示、用户提示与 JSON Schema。
 * 维护边界：提示词和 Schema 字段必须保持一致，尤其是 result、violations 与 replacementText。
 */
export function auditSystemPrompt(): string {
  return `你是“镜渊”规则审核器。你只检查给定AI正文是否违反玩家提供的硬性规则，不续写，不润色，不替正文辩护。

必须只输出一个JSON对象，结构如下：
{
  "result": "pass | revise | block",
  "reason": "一句话结论",
  "violations": [
    {
      "ruleId": "稳定、简短的规则编号",
      "rule": "被违反的规则",
      "evidence": "正文中的具体违规片段或准确概述",
      "action": "应如何修改，必须具体可执行"
    }
  ],
  "preserve": ["修正时必须保留的外部事实"],
  "rewriteInstruction": "给修正文模型的一段完整指令",
  "replacementText": "若能严格最小修正则给出完整替换正文；否则输出空字符串"
}

判定标准：
- pass：没有明确违规。
- revise：可以在不改变已经成立的外部事件、NPC行为和事件顺序的前提下定向修正。
- block：整段内容建立在违规前提上，无法局部修正而不重构剧情。

规则：
1. 只列出有明确证据的违规。
2. evidence必须足以让修正文模型定位问题。
3. action必须说明“删什么、保留什么、用什么可观察事实替代”，不能只写“不要违规”。
4. preserve只写已经成立且不能被修正模型改动的外部事实。
5. pass时violations必须为空，rewriteInstruction可为空。
6. replacementText字段必须始终存在；仅在能严格最小修正时填写完整正文，否则输出空字符串。
7. 不输出Markdown代码块，不输出JSON以外的文字。`;
}

export function auditUserPrompt(rulePrompt: string, playerText: string, assistantText: string): string {
  return `【玩家审核规则】
${rulePrompt}

【玩家本轮输入】
${playerText || '（空）'}

【待审核AI正文】
${assistantText}`;
}

export function auditJsonSchema(): Record<string, any> {
  return {
    name: 'MirrorAbyssAuditResult',
    description: '镜渊规则审核结果',
    strict: true,
    value: {
      $schema: 'http://json-schema.org/draft-04/schema#',
      type: 'object',
      properties: {
        result: { type: 'string', enum: ['pass', 'revise', 'block'] },
        reason: { type: 'string' },
        violations: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              ruleId: { type: 'string' },
              rule: { type: 'string' },
              evidence: { type: 'string' },
              action: { type: 'string' },
            },
            required: ['ruleId', 'rule', 'evidence', 'action'],
            additionalProperties: false,
          },
        },
        preserve: { type: 'array', items: { type: 'string' } },
        rewriteInstruction: { type: 'string' },
        replacementText: { type: 'string' },
      },
      required: ['result', 'reason', 'violations', 'preserve', 'rewriteInstruction', 'replacementText'],
      additionalProperties: false,
    },
  };
}
