/**
 * 模块职责：按连接 lane 串行模型请求，并记录排队与请求耗时。
 * 维护边界：只重排尚未开始的请求，不抢占正在运行的供应商请求。
 */
import type { TaskKind } from '../constants';
import { makeId, nowIso, toErrorMessage } from '../core/utils';

interface RequestJob<T = unknown> {
  id: string;
  lane: string;
  task: TaskKind;
  priority: number;
  sequence: number;
  createdMs: number;
  signal: AbortSignal;
  work: () => Promise<T>;
  resolve: (value: T | PromiseLike<T>) => void;
  reject: (reason?: unknown) => void;
  abortListener: () => void;
  trace: Record<string, any>;
}

interface LaneState {
  active: RequestJob | null;
  pending: RequestJob[];
}

const REQUEST_PRIORITIES: Record<TaskKind, number> = {
  audit: 100,
  revision: 100,
  state: 90,
  smallSummary: 30,
  largeSummary: 10,
};

function abortError(message = '模型请求已取消'): Error {
  const error = new Error(message);
  error.name = 'AbortError';
  return error;
}

/**
 * lane 内保持单请求；不同 lane 可独立运行。
 * pending 按优先级选取，已经 running 的请求不会被新任务强行中断。
 */
export class RequestLaneScheduler {
  private static readonly MAX_TRACES = 200;
  private lanes = new Map<string, LaneState>();
  private traces = new Map<string, Record<string, any>>();
  private sequence = 0;

  list(): Record<string, any>[] {
    return [...this.traces.values()].sort((a, b) => String(b.createdAt).localeCompare(String(a.createdAt)));
  }

  clearHistory(): void {
    for (const [id, trace] of this.traces) {
      if (!['queued', 'running'].includes(String(trace.state))) this.traces.delete(id);
    }
  }

  private prune(): void {
    while (this.traces.size > RequestLaneScheduler.MAX_TRACES) {
      const removable = [...this.traces.entries()].find(([, trace]) => !['queued', 'running'].includes(String(trace.state)));
      if (!removable) break;
      this.traces.delete(removable[0]);
    }
  }

  private lane(name: string): LaneState {
    let state = this.lanes.get(name);
    if (!state) {
      state = { active: null, pending: [] };
      this.lanes.set(name, state);
    }
    return state;
  }

  private selectNext(state: LaneState): RequestJob | null {
    if (!state.pending.length) return null;
    let selectedIndex = 0;
    for (let index = 1; index < state.pending.length; index += 1) {
      const candidate = state.pending[index];
      const selected = state.pending[selectedIndex];
      if (candidate.priority > selected.priority || (
        candidate.priority === selected.priority && candidate.sequence < selected.sequence
      )) selectedIndex = index;
    }
    return state.pending.splice(selectedIndex, 1)[0] ?? null;
  }

  private pump(laneName: string): void {
    const state = this.lane(laneName);
    if (state.active) return;
    const job = this.selectNext(state);
    if (!job) {
      if (!state.pending.length) this.lanes.delete(laneName);
      return;
    }
    if (job.signal.aborted) {
      job.signal.removeEventListener('abort', job.abortListener);
      job.trace.state = 'cancelled';
      job.trace.error = '模型请求已取消';
      job.trace.finishedAt = nowIso();
      job.trace.transportWaitMs = Math.max(0, Date.now() - job.createdMs);
      job.trace.totalMs = job.trace.transportWaitMs;
      job.reject(abortError());
      this.prune();
      this.pump(laneName);
      return;
    }

    state.active = job;
    const startedMs = Date.now();
    job.trace.state = 'running';
    job.trace.startedAt = nowIso();
    job.trace.transportWaitMs = Math.max(0, startedMs - job.createdMs);

    void job.work()
      .then((result) => {
        job.trace.state = 'success';
        job.resolve(result);
      })
      .catch((error) => {
        job.trace.state = error instanceof Error && error.name === 'AbortError' ? 'cancelled' : 'failed';
        job.trace.error = toErrorMessage(error);
        job.reject(error);
      })
      .finally(() => {
        const finishedMs = Date.now();
        job.signal.removeEventListener('abort', job.abortListener);
        job.trace.finishedAt = nowIso();
        job.trace.requestMs = Math.max(0, finishedMs - startedMs);
        job.trace.totalMs = Math.max(0, finishedMs - job.createdMs);
        state.active = null;
        this.prune();
        this.pump(laneName);
      });
  }

  run<T>(laneName: string, task: TaskKind, signal: AbortSignal, work: () => Promise<T>): Promise<T> {
    if (signal.aborted) return Promise.reject(abortError());
    const createdMs = Date.now();
    const id = makeId('request');
    const trace: Record<string, any> = {
      id,
      lane: laneName,
      task,
      state: 'queued',
      createdAt: nowIso(),
      transportWaitMs: 0,
      requestMs: 0,
      totalMs: 0,
      firstByteMs: undefined,
      streamMode: 'off',
    };
    this.traces.set(id, trace);

    let resolve!: (value: T | PromiseLike<T>) => void;
    let reject!: (reason?: unknown) => void;
    const promise = new Promise<T>((resolveValue, rejectValue) => {
      resolve = resolveValue;
      reject = rejectValue;
    });
    const state = this.lane(laneName);
    const job: RequestJob<T> = {
      id,
      lane: laneName,
      task,
      priority: REQUEST_PRIORITIES[task],
      sequence: this.sequence += 1,
      createdMs,
      signal,
      work,
      resolve,
      reject,
      trace,
      abortListener: () => {
        if (state.active === job) return;
        const index = state.pending.indexOf(job as RequestJob);
        if (index < 0) return;
        state.pending.splice(index, 1);
        trace.state = 'cancelled';
        trace.error = '模型请求已取消';
        trace.finishedAt = nowIso();
        trace.transportWaitMs = Math.max(0, Date.now() - createdMs);
        trace.totalMs = trace.transportWaitMs;
        signal.removeEventListener('abort', job.abortListener);
        reject(abortError());
        this.prune();
        this.pump(laneName);
      },
    };
    signal.addEventListener('abort', job.abortListener, { once: true });
    state.pending.push(job as RequestJob);
    this.prune();
    this.pump(laneName);
    return promise;
  }
}

export const requestScheduler = new RequestLaneScheduler();
