/**
 * 模块职责：从动态表格快照构建关系图与世界图的展示数据。
 * 维护边界：图谱是派生视图，不反向成为内部事实或表格真相来源。
 */
import type { TableDefinition, TableRole } from '../constants';
import type { StateSnapshot, StateRow } from '../types';
import { DEFAULT_TABLE_REGISTRY, enabledTables, normalizeTableRegistry, tableByRole } from './table-registry';

export type GraphNodeType = 'focus' | 'character' | 'item' | 'event' | 'region' | 'relationship';
export interface GraphNode { id: string; label: string; type: GraphNodeType; detail: string; status: string; existence?: string; activity?: string; memory?: string; }
export interface GraphEdge { id: string; source: string; target: string; label: string; detail: string; }
export interface RelationshipGraph { nodes: GraphNode[]; edges: GraphEdge[]; }

function nodeTypeFor(role: TableRole): GraphNodeType | null {
  if (role === 'focus') return 'focus';
  if (role === 'state') return 'character';
  if (role === 'items' || role === 'skills') return 'item';
  if (role === 'events') return 'event';
  if (role === 'regions' || role === 'spacetime' || role === 'globalChanges') return 'region';
  return null;
}
function compactLabel(value: string): string { const text = String(value || '').trim(); return text.length > 24 ? `${text.slice(0, 23)}…` : text; }
function relationText(row: StateRow): string { return `${row.title}\n${row.content}\n${row.status}\n${row.keywords.join(' ')}`.toLowerCase(); }
function mentions(row: StateRow, node: GraphNode): boolean { const label = node.label.trim().toLowerCase(); return label.length >= 2 && relationText(row).includes(label); }
function uniquePairKey(a: string, b: string, label: string): string { const [left, right] = [a, b].sort(); return `${left}|${right}|${label}`; }

export function buildRelationshipGraph(snapshot?: StateSnapshot, scope: 'relations' | 'world' = 'relations', customRegistry?: TableDefinition[]): RelationshipGraph {
  if (!snapshot) return { nodes: [], edges: [] };
  const registry = normalizeTableRegistry(customRegistry?.length ? customRegistry : DEFAULT_TABLE_REGISTRY as TableDefinition[]);
  const nodes: GraphNode[] = [];
  const rowsByNode = new Map<string, StateRow>();
  const roles: TableRole[] = scope === 'relations' ? ['focus', 'state'] : ['focus', 'state', 'items', 'skills', 'events', 'regions', 'spacetime', 'globalChanges'];
  for (const table of enabledTables(registry).filter((item) => roles.includes(item.role))) {
    const type = nodeTypeFor(table.role);
    if (!type) continue;
    for (const row of snapshot[table.key] ?? []) {
      const id = `${table.key}:${row.id}`;
      nodes.push({ id, label: String(row.title || '未命名').trim(), type, detail: row.content, status: row.status, existence: row.lifecycle?.existence, activity: row.lifecycle?.activity, memory: row.lifecycle?.memory });
      rowsByNode.set(id, row);
    }
  }

  const edges: GraphEdge[] = [];
  const seenEdges = new Set<string>();
  const relationKey = tableByRole(registry, 'relationships')?.key;
  let relationIndex = 0;
  for (const row of relationKey ? snapshot[relationKey] ?? [] : []) {
    const matched = nodes.filter((node) => mentions(row, node));
    if (matched.length >= 2) {
      const source = matched[0];
      for (const target of matched.slice(1, 4)) {
        const key = uniquePairKey(source.id, target.id, row.title);
        if (seenEdges.has(key)) continue;
        seenEdges.add(key);
        edges.push({ id: `edge:${row.id}:${target.id}`, source: source.id, target: target.id, label: compactLabel(row.title), detail: row.content });
      }
    } else {
      const relationNode: GraphNode = { id: `relationship:${row.id}`, label: compactLabel(row.title || `关系${relationIndex + 1}`), type: 'relationship', detail: row.content, status: row.status };
      relationIndex += 1;
      nodes.push(relationNode);
      if (matched.length === 1) edges.push({ id: `edge:${row.id}:single`, source: matched[0].id, target: relationNode.id, label: compactLabel(row.status || '关系'), detail: row.content });
    }
  }

  if (scope === 'world') {
    const contextual = nodes.filter((node) => ['item', 'event', 'region'].includes(node.type));
    for (const actor of nodes.filter((node) => node.type === 'character' || node.type === 'focus')) {
      const row = rowsByNode.get(actor.id);
      if (!row) continue;
      const text = relationText(row);
      for (const target of contextual) {
        if (target.label.length < 2 || !text.includes(target.label.toLowerCase())) continue;
        const key = uniquePairKey(actor.id, target.id, '关联');
        if (seenEdges.has(key)) continue;
        seenEdges.add(key);
        edges.push({ id: `context:${actor.id}:${target.id}`, source: actor.id, target: target.id, label: '关联', detail: row.content });
      }
    }
  }
  return { nodes, edges };
}
