/**
 * 模块职责：动态表格注册、旧九表迁移、字段定义归一化与注册表操作。
 * 维护边界：删除或停用表格只影响可见视图；内部事实层不依赖这里的数量和名称。
 */
import { type TableDefinition, type TableFieldDefinition, type TableRole } from '../constants';
import { deepClone, hashText, safeText } from '../core/utils';

export const CORE_FIELD_KEYS = ['id', 'title', 'content', 'keywords', 'status', 'factIds', 'eventId', 'recall'] as const;
const COMMON_FIELDS: TableFieldDefinition[] = [
  { key: 'id', label: '稳定ID', description: '同一对象沿用稳定ID', type: 'string', required: true },
  { key: 'title', label: '对象', description: '简洁标识该条事实视图', type: 'string', required: true },
  { key: 'content', label: '当前事实', description: '只写已显影且对后续有用的当前事实', type: 'string', required: true },
  { key: 'keywords', label: '关键词', description: '人物名、别名、物品、技能、区域、事件、组织或制度等明确触发词', type: 'string[]', required: true },
  { key: 'status', label: '状态', description: '当前有效状态或阶段', type: 'string', required: true },
];
const LIFECYCLE_FIELD: TableFieldDefinition = {
  key: 'lifecycle', label: '生命周期', description: '正式主体的存在、活跃、记忆、证据与回流条件', type: 'lifecycle', required: false,
};

function defaults(): TableDefinition[] {
  const definitions: Array<[string, string, string, TableRole, boolean]> = [
    ['focus', '焦点', '当前核心冲突、目标或待决事项；不得复制人物卡或其他表格事实。', 'focus', false],
    ['spacetime', '时空', '当前焦点直接相关的时间、地点与场景连续性。', 'spacetime', false],
    ['state', '状态', '正式显影且对当前连续性有独立价值的主体状态；纯旁观者不得建立。', 'state', true],
    ['items', '物品', '对当前焦点、因果或后续生成有作用的重要物品与资源。', 'items', false],
    ['skills', '技能', '已显影的技能、能力、条件、消耗与边界。', 'skills', false],
    ['relationships', '显著关系', '已经显影并会影响行为或事件结果的关系。', 'relationships', false],
    ['events', '活跃事件', '仍在推进或尚有未决事项的事件线与流程。', 'events', false],
    ['regions', '相关区域', '与当前焦点或未决事件直接相关的区域状态。', 'regions', false],
    ['globalChanges', '全局变化', '已经发生并直接影响后续的跨区域、制度或世界态势变化。', 'globalChanges', false],
    ['foundations', '相关基础设定', '当前焦点确实需要的稳定规则、制度和承重设定。', 'foundations', false],
  ];
  return definitions.map(([key, name, purpose, role, lifecycle], order) => ({
    key, name, purpose, role, enabled: true, order, isDefault: true,
    fields: [...deepClone(COMMON_FIELDS), ...(lifecycle ? [deepClone(LIFECYCLE_FIELD)] : [])],
  }));
}

export const DEFAULT_TABLE_REGISTRY: readonly TableDefinition[] = Object.freeze(defaults());
export const LEGACY_TABLE_KEY_MAP: Record<string, string> = {
  focus: 'focus', spacetime: 'spacetime', characters: 'state', state: 'state', items: 'items', skills: 'skills',
  relationships: 'relationships', events: 'events', regions: 'regions', globalChanges: 'globalChanges', foundations: 'foundations',
};

function normalizeField(value: unknown, index: number): TableFieldDefinition | null {
  const source = value && typeof value === 'object' ? value as Record<string, unknown> : {};
  const key = safeText(source.key, 60).trim().replace(/[^a-zA-Z0-9_-]/g, '');
  if (!key) return null;
  const type = ['string', 'string[]', 'lifecycle'].includes(String(source.type)) ? source.type as TableFieldDefinition['type'] : 'string';
  return {
    key,
    label: safeText(source.label || key, 80).trim() || `字段${index + 1}`,
    description: safeText(source.description, 500).trim(),
    type,
    required: Boolean(source.required),
  };
}

export function normalizeTableRegistry(value: unknown): TableDefinition[] {
  const source = Array.isArray(value) && value.length ? value : DEFAULT_TABLE_REGISTRY;
  const output: TableDefinition[] = [];
  const used = new Set<string>();
  source.forEach((item, index) => {
    const row = item && typeof item === 'object' ? item as Record<string, unknown> : {};
    let key = safeText(row.key, 80).trim().replace(/[^a-zA-Z0-9_-]/g, '');
    if (!key) key = `custom_${hashText(`${row.name}|${index}`)}`;
    if (used.has(key)) key = `${key}_${index + 1}`;
    used.add(key);
    const fields = (Array.isArray(row.fields) ? row.fields : COMMON_FIELDS)
      .map(normalizeField).filter((field): field is TableFieldDefinition => Boolean(field));
    for (const common of COMMON_FIELDS) if (!fields.some((field) => field.key === common.key)) fields.push(deepClone(common));
    const role = ['focus','spacetime','state','items','skills','relationships','events','regions','globalChanges','foundations','custom'].includes(String(row.role))
      ? row.role as TableRole : 'custom';
    if (role === 'state' && !fields.some((field) => field.key === 'lifecycle')) fields.push(deepClone(LIFECYCLE_FIELD));
    output.push({
      key,
      name: safeText(row.name || DEFAULT_TABLE_REGISTRY.find((table) => table.key === key)?.name || `自定义表格 ${index + 1}`, 80).trim(),
      purpose: safeText(row.purpose, 1000).trim() || '记录玩家定义、对后续生成有用的已显影事实。',
      role,
      enabled: row.enabled !== false,
      order: Number.isFinite(Number(row.order)) ? Number(row.order) : index,
      isDefault: Boolean(row.isDefault || DEFAULT_TABLE_REGISTRY.some((table) => table.key === key)),
      fields,
    });
  });
  return output.sort((a, b) => a.order - b.order).map((table, order) => ({ ...table, order }));
}

export function enabledTables(registry: TableDefinition[]): TableDefinition[] {
  return normalizeTableRegistry(registry).filter((table) => table.enabled);
}
export function tableByKey(registry: TableDefinition[], key: string): TableDefinition | undefined {
  return normalizeTableRegistry(registry).find((table) => table.key === key);
}
export function tableByRole(registry: TableDefinition[], role: TableRole, enabledOnly = true): TableDefinition | undefined {
  return normalizeTableRegistry(registry).find((table) => (!enabledOnly || table.enabled) && table.role === role);
}
export function tableKeyForRole(registry: TableDefinition[], role: TableRole, fallback = ''): string {
  return tableByRole(registry, role)?.key || fallback;
}
export function restoreDefaultTableRegistry(): TableDefinition[] { return deepClone(DEFAULT_TABLE_REGISTRY as TableDefinition[]); }
export function registryFingerprint(registry: TableDefinition[]): string {
  return hashText(JSON.stringify(normalizeTableRegistry(registry).map(({ key, name, purpose, role, enabled, order, fields }) => ({ key, name, purpose, role, enabled, order, fields }))));
}

export function parseCustomFields(fieldText = ''): TableFieldDefinition[] {
  const used = new Set<string>();
  return fieldText.split(/\n+/).map((value) => value.trim()).filter(Boolean).map((line, index) => {
    const parts = line.split(/[:：]/).map((part) => part.trim());
    const rawKey = parts[0] || `field_${index + 1}`;
    const key = safeText(rawKey, 60).trim().replace(/[^a-zA-Z0-9_-]/g, '') || `field_${index + 1}`;
    if (CORE_FIELD_KEYS.includes(key as any) || key === 'lifecycle' || used.has(key)) return null;
    used.add(key);
    const label = safeText(parts[1] || key, 80).trim() || key;
    const type = parts[2] === 'string[]' ? 'string[]' as const : 'string' as const;
    const description = safeText(parts.slice(3).join('：') || label, 500).trim();
    return { key, label, description, type, required: false };
  }).filter((field): field is TableFieldDefinition => Boolean(field));
}

export function customFieldText(table: TableDefinition): string {
  return table.fields.filter((field) => !CORE_FIELD_KEYS.includes(field.key as any) && field.key !== 'lifecycle')
    .map((field) => `${field.key}:${field.label}:${field.type}:${field.description}`).join('\n');
}

export function updateTableFields(registry: TableDefinition[], key: string, fieldText: string): TableDefinition[] {
  const current = normalizeTableRegistry(registry).find((table) => table.key === key);
  if (!current) return normalizeTableRegistry(registry);
  const fields = [...deepClone(COMMON_FIELDS), ...(current.role === 'state' ? [deepClone(LIFECYCLE_FIELD)] : []), ...parseCustomFields(fieldText)];
  return updateTableDefinition(registry, key, { fields });
}

export function createCustomTable(registry: TableDefinition[], name: string, purpose: string, fieldText = ''): TableDefinition[] {
  const next = normalizeTableRegistry(registry);
  const key = `custom_${hashText(`${name}|${Date.now()}|${next.length}`)}`;
  next.push({
    key,
    name: safeText(name, 80).trim() || '自定义表格',
    purpose: safeText(purpose, 1000).trim() || '记录玩家定义的已显影事实。',
    role: 'custom', enabled: true, order: next.length, isDefault: false,
    fields: [...deepClone(COMMON_FIELDS), ...parseCustomFields(fieldText)],
  });
  return normalizeTableRegistry(next);
}
export function updateTableDefinition(registry: TableDefinition[], key: string, patch: Partial<TableDefinition>): TableDefinition[] {
  return normalizeTableRegistry(registry).map((table) => table.key === key
    ? { ...table, ...patch, key: table.key, isDefault: table.isDefault, fields: patch.fields ? patch.fields.map((field, index) => normalizeField(field, index)).filter(Boolean) as TableFieldDefinition[] : table.fields }
    : table);
}
export function removeTableDefinition(registry: TableDefinition[], key: string): TableDefinition[] {
  return normalizeTableRegistry(registry).filter((table) => table.key !== key).map((table, order) => ({ ...table, order }));
}
export function moveTableDefinition(registry: TableDefinition[], key: string, direction: -1 | 1): TableDefinition[] {
  const next = normalizeTableRegistry(registry);
  const index = next.findIndex((table) => table.key === key);
  const target = index + direction;
  if (index < 0 || target < 0 || target >= next.length) return next;
  [next[index], next[target]] = [next[target], next[index]];
  return next.map((table, order) => ({ ...table, order }));
}

/** 旧 characters 等键只迁移到新默认视图；未注册键不会进入可见快照。 */
export function migrateSnapshotTables(value: unknown, registry: TableDefinition[]): Record<string, any[]> {
  const source = value && typeof value === 'object' ? value as Record<string, unknown> : {};
  const output: Record<string, any[]> = {};
  for (const table of normalizeTableRegistry(registry)) output[table.key] = [];
  for (const [sourceKey, rawRows] of Object.entries(source)) {
    if (!Array.isArray(rawRows)) continue;
    const targetKey = LEGACY_TABLE_KEY_MAP[sourceKey] ?? sourceKey;
    if (!(targetKey in output)) continue;
    output[targetKey].push(...rawRows);
  }
  return output;
}
