/**
 * 模块职责：按动态注册表归一化可见事实视图，并合并人工/锁定数据。
 * 维护边界：快照只是视图；source=manual 或 locked=true 的行必须保留，内部事实真相在 ChatState.internalFacts。
 */
import { type TableDefinition, type TableKey } from '../constants';
import type { ActivityState, CharacterLifecycle, EvidenceLevel, ExistenceState, MemoryState, StateRow, StateSnapshot } from '../types';
import { makeId, nowIso, safeText } from '../core/utils';
import { DEFAULT_TABLE_REGISTRY, enabledTables, migrateSnapshotTables, normalizeTableRegistry, tableByKey, tableByRole } from './table-registry';

const EXISTENCE_STATES = new Set<ExistenceState>([
  '存活', '死亡已确认', '存在未知', '失踪', '身份存疑', '虚构或误认已确认', '存在被抹除', '未标注', '不适用',
]);
const ACTIVITY_STATES = new Set<ActivityState>([
  '当前在场', '当前相关', '离场但仍活跃', '休眠', '长期休眠', '已归档', '未标注', '不适用',
]);
const MEMORY_STATES = new Set<MemoryState>([
  '广泛记得', '部分人物记得', '仅记录留存', '仅痕迹留存', '无人可确认记得', '记忆被篡改', '记忆被抹除', '未标注', '不适用',
]);
const EVIDENCE_LEVELS = new Set<EvidenceLevel>(['已确认', '可靠记录', '多方陈述', '单方陈述', '推测', '未知']);
const STANDARD_FIELDS = new Set(['id', 'title', 'name', 'content', 'summary', 'keywords', 'status', 'source', 'locked', 'lifecycle', 'updatedAt', 'factIds', 'fact_ids', 'eventId', 'event_id', 'recall', 'fields']);

function registryOrDefault(registry?: TableDefinition[]): TableDefinition[] {
  return normalizeTableRegistry(registry?.length ? registry : DEFAULT_TABLE_REGISTRY as TableDefinition[]);
}

/** 非枚举 characters 别名只用于 rc.19 测试/API 兼容，不会进入模型 JSON。 */
function attachLegacyAliases(snapshot: StateSnapshot, registry: TableDefinition[]): StateSnapshot {
  const stateKey = tableByRole(registry, 'state', false)?.key;
  if (stateKey && stateKey in snapshot && !Object.prototype.hasOwnProperty.call(snapshot, 'characters')) {
    Object.defineProperty(snapshot, 'characters', {
      configurable: true,
      enumerable: false,
      get: () => snapshot[stateKey],
      set: (value) => { snapshot[stateKey] = Array.isArray(value) ? value : []; },
    });
  }
  return snapshot;
}

export function emptySnapshot(registry?: TableDefinition[], includeDisabled = true): StateSnapshot {
  const tables = registryOrDefault(registry).filter((table) => includeDisabled || table.enabled);
  return attachLegacyAliases(Object.fromEntries(tables.map((table) => [table.key, []])) as StateSnapshot, tables);
}

export function normalizeKeywords(value: unknown): string[] {
  if (!Array.isArray(value)) return [];
  return [...new Set(value.map((item) => safeText(item, 80).trim()).filter(Boolean))].slice(0, 24);
}
function normalizeStringList(value: unknown, limit = 20, itemLimit = 240): string[] {
  if (!Array.isArray(value)) return [];
  return [...new Set(value.map((item) => safeText(item, itemLimit).trim()).filter(Boolean))].slice(0, limit);
}
function enumValue<T extends string>(value: unknown, allowed: Set<T>, fallback: T): T {
  const text = safeText(value, 80).trim() as T;
  return allowed.has(text) ? text : fallback;
}

export function defaultLifecycle(): CharacterLifecycle {
  return { existence: '未标注', activity: '未标注', memory: '未标注', evidenceLevel: '未知', evidence: '', returnConditions: [], returnBlockers: [] };
}
export function normalizeLifecycle(value: unknown, previous?: CharacterLifecycle): CharacterLifecycle {
  const source = value && typeof value === 'object' ? value as Record<string, unknown> : {};
  const base = previous ?? defaultLifecycle();
  return {
    existence: enumValue(source.existence ?? base.existence, EXISTENCE_STATES, base.existence),
    activity: enumValue(source.activity ?? base.activity, ACTIVITY_STATES, base.activity),
    memory: enumValue(source.memory ?? base.memory, MEMORY_STATES, base.memory),
    evidenceLevel: enumValue(source.evidenceLevel ?? base.evidenceLevel, EVIDENCE_LEVELS, base.evidenceLevel),
    evidence: safeText(source.evidence ?? base.evidence, 4000).trim(),
    returnConditions: normalizeStringList(source.returnConditions ?? base.returnConditions),
    returnBlockers: normalizeStringList(source.returnBlockers ?? base.returnBlockers),
  };
}

function normalizeRecall(value: unknown, title: string, keywords: string[]) {
  const source = value && typeof value === 'object' ? value as Record<string, unknown> : {};
  const any = normalizeStringList(source.any, 24, 100);
  return {
    any: any.length ? any : normalizeKeywords([title, ...keywords]),
    all: normalizeStringList(source.all, 16, 100),
    exclude: normalizeStringList(source.exclude, 16, 100),
  };
}

function normalizeCustomFields(source: Record<string, unknown>, table: TableDefinition, previous?: StateRow): Record<string, unknown> {
  const prior = previous?.fields && typeof previous.fields === 'object' ? previous.fields : {};
  const nested = source.fields && typeof source.fields === 'object' ? source.fields as Record<string, unknown> : {};
  const output: Record<string, unknown> = {};
  for (const field of table.fields) {
    if (STANDARD_FIELDS.has(field.key) || field.key === 'lifecycle') continue;
    const raw = source[field.key] ?? nested[field.key] ?? prior[field.key];
    if (field.type === 'string[]') output[field.key] = normalizeStringList(raw, 30, 500);
    else output[field.key] = safeText(raw, 4000).trim();
  }
  return output;
}

export function normalizeRow(value: unknown, tableKey: TableKey, index: number, previous?: StateRow, registry?: TableDefinition[]): StateRow {
  const tables = registryOrDefault(registry);
  const table = tableByKey(tables, tableKey) ?? { key: tableKey, name: tableKey, role: 'custom', fields: [] } as unknown as TableDefinition;
  const source = value && typeof value === 'object' ? value as Record<string, unknown> : {};
  const now = nowIso();
  const id = safeText(source.id || previous?.id || makeId(tableKey), 160).trim() || makeId(tableKey);
  const manual = source.source === 'manual' || previous?.source === 'manual';
  const title = safeText(source.title || source.name || previous?.title || `${table.name} ${index + 1}`, 240).trim();
  const keywords = normalizeKeywords(source.keywords ?? previous?.keywords ?? []);
  const supportsLifecycle = table.role === 'state' || table.fields.some((field) => field.type === 'lifecycle');
  const lifecycleInput = source.lifecycle ?? previous?.lifecycle;
  const factIds = normalizeStringList(source.factIds ?? source.fact_ids ?? previous?.factIds, 40, 160);
  const eventId = safeText(source.eventId ?? source.event_id ?? previous?.eventId, 160).trim() || undefined;
  return {
    id,
    title,
    content: safeText(source.content || source.summary || previous?.content || '', 12000).trim(),
    keywords,
    status: safeText(source.status || previous?.status || 'active', 120).trim() || 'active',
    source: manual ? 'manual' : 'auto',
    locked: Boolean(source.locked ?? previous?.locked ?? manual),
    lifecycle: supportsLifecycle && lifecycleInput ? normalizeLifecycle(lifecycleInput, previous?.lifecycle) : undefined,
    updatedAt: safeText(source.updatedAt || previous?.updatedAt || now, 80) || now,
    fields: normalizeCustomFields(source, table, previous),
    factIds,
    eventId,
    recall: normalizeRecall(source.recall ?? previous?.recall, title, keywords),
  };
}

export function normalizeSnapshot(value: unknown, previousSnapshot?: StateSnapshot, registry?: TableDefinition[], includeDisabled = true): StateSnapshot {
  const tables = registryOrDefault(registry).filter((table) => includeDisabled || table.enabled);
  const source = migrateSnapshotTables(value, tables);
  const previous = previousSnapshot ? migrateSnapshotTables(previousSnapshot, tables) : {};
  const output = emptySnapshot(tables, true);
  for (const table of tables) {
    const key = table.key;
    const rows = Array.isArray(source[key]) ? source[key] : [];
    const previousMap = new Map((previous[key] ?? []).map((row: StateRow) => [row.id, row]));
    const used = new Set<string>();
    output[key] = rows.map((row: unknown, index: number) => {
      const rawId = row && typeof row === 'object' ? safeText((row as any).id, 160) : '';
      const normalized = normalizeRow(row, key, index, rawId ? previousMap.get(rawId) : undefined, tables);
      if (used.has(normalized.id)) normalized.id = makeId(key);
      used.add(normalized.id);
      return normalized;
    });
  }
  return attachLegacyAliases(output, tables);
}

function identityTitle(value: string): string {
  return String(value || '').toLowerCase().replace(/[\s·•._—–\-|｜:：()（）【】\[\]]+/g, '');
}
function stateRows(snapshot: StateSnapshot, registry: TableDefinition[]): StateRow[] {
  const key = tableByRole(registry, 'state', false)?.key;
  return key ? snapshot[key] ?? [] : [];
}

/** 保留已建立主体，人工/锁定行优先；仅视图层维护，不代表自动创建人物卡。 */
export function preservePersistentCharacters(previous: StateSnapshot, next: StateSnapshot, registry?: TableDefinition[]): StateSnapshot {
  const tables = registryOrDefault(registry);
  const key = tableByRole(tables, 'state', false)?.key;
  if (!key) return next;
  const nextRows = next[key] ?? (next[key] = []);
  const oldRows = previous[key] ?? previous.characters ?? [];
  const byId = new Map(nextRows.map((row) => [row.id, row]));
  const byTitle = new Map(nextRows.map((row) => [identityTitle(row.title), row]));
  for (const oldRow of oldRows) {
    if (byId.has(oldRow.id)) continue;
    const titleMatch = byTitle.get(identityTitle(oldRow.title));
    if (titleMatch) {
      titleMatch.id = oldRow.id;
      if (oldRow.source === 'manual' || oldRow.locked) Object.assign(titleMatch, structuredClone(oldRow));
      else if (!titleMatch.lifecycle && oldRow.lifecycle) titleMatch.lifecycle = structuredClone(oldRow.lifecycle);
      byId.set(oldRow.id, titleMatch);
      continue;
    }
    const restored = structuredClone(oldRow);
    nextRows.push(restored);
    byId.set(restored.id, restored);
    byTitle.set(identityTitle(restored.title), restored);
  }
  const seenTitles = new Set<string>();
  next[key] = nextRows.filter((row) => {
    const title = identityTitle(row.title);
    if (!title || !seenTitles.has(title)) { if (title) seenTitles.add(title); return true; }
    return false;
  });
  return attachLegacyAliases(next, tables);
}

function characterTitleAliases(title: string): string[] {
  const raw = String(title || '').trim();
  const parts = raw.split(/[｜|:：—–-]/).map(identityTitle).filter(Boolean);
  const stripped = identityTitle(raw.replace(/(?:人物|角色|人物状态|角色状态|档案|信息|当前状态)$/g, ''));
  return [...new Set([identityTitle(raw), stripped, ...parts].filter(Boolean))];
}
export function removeFocusCharacterDuplicates(snapshot: StateSnapshot, registry?: TableDefinition[]): StateSnapshot {
  const tables = registryOrDefault(registry);
  const focusKey = tableByRole(tables, 'focus', false)?.key;
  if (!focusKey) return snapshot;
  const characters = stateRows(snapshot, tables);
  const aliases = new Set(characters.flatMap((row) => characterTitleAliases(row.title)));
  const contents = new Set(characters.map((row) => identityTitle(row.content)).filter((value) => value.length >= 12));
  snapshot[focusKey] = (snapshot[focusKey] ?? []).filter((row) => {
    if (row.source === 'manual' || row.locked) return true;
    const title = identityTitle(row.title);
    const content = identityTitle(row.content);
    return !(title && aliases.has(title)) && !(content.length >= 12 && contents.has(content));
  });
  return snapshot;
}

export function snapshotRowCount(snapshot?: StateSnapshot, registry?: TableDefinition[], enabledOnly = false): number {
  if (!snapshot) return 0;
  const tables = registryOrDefault(registry).filter((table) => !enabledOnly || table.enabled);
  return tables.reduce((sum, table) => sum + (snapshot[table.key]?.length ?? 0), 0);
}
export function upsertManualRow(snapshot: StateSnapshot, tableKey: TableKey, row: Partial<StateRow> & { id?: string }, registry?: TableDefinition[]): StateSnapshot {
  const tables = registryOrDefault(registry);
  const next = normalizeSnapshot(snapshot, snapshot, tables);
  next[tableKey] ||= [];
  const index = next[tableKey].findIndex((item) => item.id === row.id);
  const normalized = normalizeRow({ ...row, source: 'manual', locked: row.locked ?? true, updatedAt: nowIso() }, tableKey, index >= 0 ? index : next[tableKey].length, index >= 0 ? next[tableKey][index] : undefined, tables);
  if (index >= 0) next[tableKey][index] = normalized; else next[tableKey].push(normalized);
  return next;
}
export function deleteRow(snapshot: StateSnapshot, tableKey: TableKey, rowId: string, registry?: TableDefinition[]): StateSnapshot {
  const next = normalizeSnapshot(snapshot, snapshot, registry);
  next[tableKey] = (next[tableKey] ?? []).filter((row) => row.id !== rowId);
  return next;
}

export function stateSchemaDescription(registry?: TableDefinition[]): string {
  const example: Record<string, unknown[]> = {};
  for (const table of enabledTables(registryOrDefault(registry))) {
    const sample: Record<string, unknown> = {
      id: `${table.key}-1`, title: table.name, content: table.purpose, keywords: [table.name], status: 'active', factIds: ['fact_1'], eventId: 'event_1',
    };
    for (const field of table.fields) {
      if (STANDARD_FIELDS.has(field.key) || field.key === 'lifecycle') continue;
      sample[field.key] = field.type === 'string[]' ? [] : '';
    }
    example[table.key] = [sample];
  }
  return JSON.stringify(example, null, 2);
}

function relevanceText(row: StateRow): string {
  return `${row.title} ${row.content} ${row.status} ${row.keywords.join(' ')}`;
}
function isPassiveObserver(row: StateRow): boolean {
  if (row.source === 'manual' || row.locked) return false;
  return /(纯观众|旁观|围观|观众|看客|路人|背景人物|未介入|只听见|喝彩|起哄|议论|人群反应|站在一旁|远处观看)/i.test(relevanceText(row));
}
/** 最后一层确定性过滤：纯旁观者及其临时反应不得留在活跃视图。 */
export function filterPassiveObservers(snapshot: StateSnapshot, registry?: TableDefinition[]): StateSnapshot {
  const tables = registryOrDefault(registry);
  for (const table of tables) {
    if (!table.enabled) continue;
    snapshot[table.key] = (snapshot[table.key] ?? []).filter((row) => !isPassiveObserver(row));
  }
  return snapshot;
}
